mapper.select:
/* on.standard.system.comcode.selectComCode */
SELECT COM_CD , UPP_COM_CD, CD_NM, SORT_NO, CD_COMMENT, USE_YN
     , FILTER_1, FILTER_2, FILTER_3, FILTER_4, FILTER_5
     , FILTER_6, FILTER_7, FILTER_8, FILTER_9, FILTER_10
     , CONCAT(COM_CD, ' (',CD_NM,')') as CD_DESC
  FROM STB_B_CD_MNG
 WHERE UPP_COM_CD = #{uppComCd}


            AND USE_YN = #{useYn}


            AND USE_YN = 'Y'


    AND FILTER_1 = #{filter1} 
    AND FILTER_1 != #{filter1_ne} 
    AND FILTER_1 LIKE CONCAT('%',#{filter1_like},'%')
     AND FILTER_1 < #{filter1_lt}  
     AND FILTER_1 > #{filter1_gt}  

    AND FILTER_2 = #{filter2} 
    AND FILTER_2 != #{filter2_ne} 
    AND FILTER_2 LIKE CONCAT('%',#{filter2_like},'%')
     AND FILTER_2 < #{filter2_lt}  
     AND FILTER_2 > #{filter2_gt}  

    AND FILTER_3 = #{filter3} 
    AND FILTER_3 != #{filter3_ne} 
    AND FILTER_3 LIKE CONCAT('%',#{filter3_like},'%')
     AND FILTER_3 < #{filter3_lt}  
     AND FILTER_3 > #{filter3_gt}  

    AND FILTER_4 = #{filter4} 
    AND FILTER_4 != #{filter4_ne} 
    AND FILTER_4 LIKE CONCAT('%',#{filter4_like},'%')
     AND FILTER_4 < #{filter4_lt}  
     AND FILTER_4 > #{filter4_gt}  

    AND FILTER_5 = #{filter5} 
    AND FILTER_5 != #{filter5_ne} 
    AND FILTER_5 LIKE CONCAT('%',#{filter5_like},'%')
     AND FILTER_5 < #{filter5_lt}  
     AND FILTER_5 > #{filter5_gt}  

    AND FILTER_6 = #{filter6} 
    AND FILTER_6 != #{filter6_ne} 
    AND FILTER_6 LIKE CONCAT('%',#{filter6_like},'%')
     AND FILTER_6 < #{filter6_lt}  
     AND FILTER_6 > #{filter6_gt}  

   AND FILTER_7 = #{filter7} 
    AND FILTER_7 != #{filter7_ne} 
    AND FILTER_7 LIKE CONCAT('%',#{filter7_like},'%')
     AND FILTER_7 < #{filter7_lt}  
     AND FILTER_7 > #{filter7_gt}  

   AND FILTER_8 = #{filter8} 
    AND FILTER_8 != #{filter8_ne} 
    AND FILTER_8 LIKE CONCAT('%',#{filter8_like},'%')
     AND FILTER_8 < #{filter8_lt}  
     AND FILTER_8 > #{filter8_gt}  

   AND FILTER_9 = #{filter9} 
    AND FILTER_9 != #{filter9_ne} 
    AND FILTER_9 LIKE CONCAT('%',#{filter9_like},'%')
     AND FILTER_9 < #{filter9_lt}  
     AND FILTER_9 > #{filter9_gt}  

   AND FILTER_10 = #{filter10} 
    AND FILTER_10 != #{filter10_ne} 
    AND FILTER_10 LIKE CONCAT('%',#{filter10_like},'%')
     AND FILTER_10 < #{filter10_lt}  
     AND FILTER_10 > #{filter10_gt}  
ORDER BY SORT_NO
